  String? drawId;
  int? digits;
  int? status;
  String? drawPlayGroupId;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['gameId'] = gameId;
    map['gameName'] = gameName;
    map['price'] = price;
    map['winPrice'] = winPrice;
    map['drawStartTime'] = drawStartTime;
    map['drawId'] = drawId;
    map['drawPlayGroupId'] = drawPlayGroupId;
    map['digits'] = digits;
    map['status'] = status;
    return map;
  }
}
